import {
  Container,
  Row,
  Col,
  Card,
  Button,
  Badge,
  Pagination,
} from "react-bootstrap";
import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getAllEvents } from "../services/eventService";

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState("on_sale");
  const [currentPage, setCurrentPage] = useState(1);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await getAllEvents();
        setEvents(response.data);
        setLoading(false);
      } catch (error) {
        console.error("Failed to fetch events", error);
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <Container>
      <Row>
        {events
          .filter((event) => event.status === activeFilter)
          .map((event) => (
            <Col key={event.id} sm={12} md={6} lg={4}>
              <Card>
                <Card.Img variant="top" src={event.banner_image} />
                <Card.Body>
                  <Card.Title>{event.name}</Card.Title>
                  <Card.Text>{event.description}</Card.Text>
                  <Button onClick={() => navigate(`/events/${event.id}`)}>
                    View Details
                  </Button>
                  <Badge variant="info">{event.status}</Badge>
                </Card.Body>
              </Card>
            </Col>
          ))}
      </Row>
      <Pagination>
        <Pagination.Prev onClick={() => handlePageChange(currentPage - 1)} />
        <Pagination.Item>{currentPage}</Pagination.Item>
        <Pagination.Next onClick={() => handlePageChange(currentPage + 1)} />
      </Pagination>
    </Container>
  );
}

export default HomePage;
